#pragma once

// Lloyd-Max optimal codebooks for the actual ExLlamaV3 post-WHT/max-norm distribution
// Computed via Lloyd-Max algorithm on 100k-bin histogram of 10M samples
// of: X_i / max_j(|X_j|)  where X_j = WHT(N(0,1)) / sqrt(32)
//
// Distribution: bounded [-1,1], std≈0.43, platykurtic (kurtosis excess≈-0.27)
//
// For each bit-width N, there are 2^N centroids and 2^N-1 boundaries.
// Centroids are NOT pinned to ±1; they sit at the optimal Lloyd-Max positions
//
//   2-bit: 8.3% MSE reduction vs uniform  (+0.38 dB SQNR)
//   3-bit: 8.3% MSE reduction vs uniform  (+0.37 dB SQNR)
//   4-bit: 13.3% MSE reduction vs uniform  (+0.62 dB SQNR)
//   5-bit: 17.2% MSE reduction vs uniform  (+0.82 dB SQNR)
//   6-bit: 19.5% MSE reduction vs uniform  (+0.94 dB SQNR)
//   7-bit: 20.0% MSE reduction vs uniform  (+0.97 dB SQNR)
//   8-bit: 10.3% MSE reduction vs uniform  (+0.47 dB SQNR)
//
// Use __constant__ memory for fast cached access from all threads.
// Max 256 values per array (8-bit = 256 levels).

