// ---------------------------------------------------------------------------
// Dispatch functions
// ---------------------------------------------------------------------------

__device__ __forceinline__ const float* _lm_get_boundaries(int num_bits)
{
    switch (num_bits) {
        case 2: return lm_boundaries_2bit;
        case 3: return lm_boundaries_3bit;
        case 4: return lm_boundaries_4bit;
        case 5: return lm_boundaries_5bit;
        case 6: return lm_boundaries_6bit;
        case 7: return lm_boundaries_7bit;
        case 8: return lm_boundaries_8bit;
        default: return lm_boundaries_2bit;
    }
}

__device__ __forceinline__ const float* _lm_get_centroids(int num_bits)
{
    switch (num_bits) {
        case 2: return lm_centroids_2bit;
        case 3: return lm_centroids_3bit;
        case 4: return lm_centroids_4bit;
        case 5: return lm_centroids_5bit;
        case 6: return lm_centroids_6bit;
        case 7: return lm_centroids_7bit;
        case 8: return lm_centroids_8bit;
        default: return lm_centroids_2bit;
    }
}

__device__ __forceinline__ int lm_quantize(float v, int num_bits)
{
    const float* bounds = _lm_get_boundaries(num_bits);
    int num_levels = 1 << num_bits;
    int lo = 0, hi = num_levels - 1;
    while (lo < hi) {
        int mid = (lo + hi) / 2;
        if (mid < num_levels - 1 && v >= bounds[mid])
            lo = mid + 1;
        else
            hi = mid;
    }
    return lo;
}

__device__ __forceinline__ float lm_dequantize(int code, int num_bits)
{
    return _lm_get_centroids(num_bits)[code];
}
